#include<bits/stdc++.h>
using namespace std;
int f(int n){
	int c=n,ans=0;
	for(int i=2;i*i<=c;i++){
		if(n%i==0){
			ans++;
			while(n%i==0)n/=i;
		}
	}
	if(n>1)ans++;
	return ans;
}
int main(void){
	ios::sync_with_stdio(0);
	cin.tie(0);cout.tie(0);
	int T,n;
	cin>>T;
	while(T--){
		cin>>n;
		if(f(n)==2)cout<<"1\n";
		else cout<<"0\n";
	}
	return false;
}
